function hasHmcRanks(ranks) {
  if (!ranks || ranks.length === 0) return false;
  return ranks.some(
    (r2) => r2.name.startsWith("E-1 ") || r2.name.startsWith("O-1 ") || r2.name.startsWith("GC-1 ") || r2.name.startsWith("G-1 ") || r2.name.includes("H.M.C")
  );
}
